/* Parse command format: "SET key=value" or "GET" or "STATUS" */
static void process_command(char *cmd)
{
    /* Trim trailing whitespace/CR/LF */
    size_t len = strlen(cmd);
    while (len > 0 && (cmd[len - 1] == '\r' || cmd[len - 1] == '\n' || cmd[len - 1] == ' ')) {
        cmd[--len] = '\0';
    }

    if (len == 0)
        return;

    if (strcmp(cmd, "STATUS") == 0 || strcmp(cmd, "GET") == 0) {
        print_config();
        return;
    }

    if (strcmp(cmd, "HELP") == 0) {
        serial_write_str("Commands:\r\n");
        serial_write_str("  SET key=value  - Set configuration parameter\r\n");
        serial_write_str("  GET / STATUS   - Show current configuration\r\n");
        serial_write_str("  HELP           - Show this help\r\n");
        serial_write_str("Keys: sample_rate, sensor_id, threshold_low,\r\n");
        serial_write_str("      threshold_high, power_mode, led_enable,\r\n");
        serial_write_str("      device_name\r\n");
        return;
    }

    /* Check for SET command */
    if (strncmp(cmd, "SET ", 4) == 0) {
        char *payload = cmd + 4;

        /* Skip leading spaces */
        while (*payload == ' ')
            payload++;

        char *eq = strchr(payload, '=');
        if (eq == NULL) {
            serial_write_str("ERR syntax: SET key=value\r\n");
            return;
        }

        *eq = '\0';
        char *key = payload;
        char *value = eq + 1;

        /* Trim trailing spaces from key */
        char *key_end = eq - 1;
        while (key_end > key && *key_end == ' ')
            *key_end-- = '\0';

        /* Skip leading spaces in value */
        while (*value == ' ')
            value++;

        if (strlen(key) == 0 || strlen(value) == 0) {
            serial_write_str("ERR empty key or value\r\n");
            return;
        }

        apply_config_value(key, value);
        return;
    }

    serial_write_str("ERR unknown command: ");
    serial_write_str(cmd);
    serial_write_str("\r\n");
    serial_write_str("Type HELP for usage\r\n");
}

